import{_ as t,c as a,a0 as o,o as i}from"./chunks/framework.B6JXc2q-.js";const q=JSON.parse('{"title":"Playback Coordinator Interface (Updated)","description":"","frontmatter":{},"headers":[],"relativePath":"spec/playback_coordinator_interface.md","filePath":"spec/playback_coordinator_interface.md"}'),r={name:"spec/playback_coordinator_interface.md"};function l(c,e,n,d,s,u){return i(),a("div",null,e[0]||(e[0]=[o('<h1 id="playback-coordinator-interface-updated" tabindex="-1">Playback Coordinator Interface (Updated) <a class="header-anchor" href="#playback-coordinator-interface-updated" aria-label="Permalink to &quot;Playback Coordinator Interface (Updated)&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Defines unified interaction between:</p><ul><li>API layer</li><li>Source adapters</li><li>Playback state machine</li></ul><hr><h2 id="playresolution" tabindex="-1">PlayResolution <a class="header-anchor" href="#playresolution" aria-label="Permalink to &quot;PlayResolution&quot;">​</a></h2><p>Adapter output:</p><p>{ &quot;source_type&quot;: &quot;...&quot;, &quot;playback_kind&quot;: &quot;...&quot;, &quot;tracks&quot;: [...], &quot;current_index&quot;: 0, &quot;context&quot;: { &quot;type&quot;: &quot;...&quot;, &quot;id&quot;: &quot;...&quot;, &quot;name&quot;: &quot;...&quot; } }</p><hr><h2 id="adapter-responsibilities" tabindex="-1">Adapter Responsibilities <a class="header-anchor" href="#adapter-responsibilities" aria-label="Permalink to &quot;Adapter Responsibilities&quot;">​</a></h2><ul><li>Resolve query</li><li>Select context</li><li>Provide queue facts</li></ul><hr><h2 id="framework-responsibilities" tabindex="-1">Framework Responsibilities <a class="header-anchor" href="#framework-responsibilities" aria-label="Permalink to &quot;Framework Responsibilities&quot;">​</a></h2><ul><li>Apply play_mode</li><li>Compute next/previous</li><li>Maintain state</li></ul><hr><h2 id="player-state-projection" tabindex="-1">Player State Projection <a class="header-anchor" href="#player-state-projection" aria-label="Permalink to &quot;Player State Projection&quot;">​</a></h2><p>播放协调器内部维护的 <code>current_index</code> 和 <code>context</code> 事实，最终需要投影到 <code>GET /api/v1/player/state</code> 的聚合结果中：</p><ul><li><code>current_index</code> → <code>data.current_index</code></li><li><code>context.type</code> → <code>data.context_type</code></li><li><code>context.id</code> → <code>data.context_id</code></li><li><code>context.name</code> → <code>data.context_name</code></li></ul><p>同时需要生成稳定的 <code>current_track_id</code>，用于前端可靠判断切歌：</p><ul><li>使用 <code>context_id + track_title</code> 的组合哈希生成</li><li>同一首歌在同一次连续播放期间保持稳定</li><li>切到下一首后必须变化</li></ul><p>不要求暴露完整 tracks 队列，但至少要能输出当前 track identity + context facts，供 WebUI / HA / 第三方调用方做稳定状态同步。</p>',21)]))}const h=t(r,[["render",l]]);export{q as __pageData,h as default};
